examples.code:
// Step 1: Create object file with PIC
gcc -fPIC -c foo.c -o foo.o

// Step 2: Create shared library from object file
gcc -shared -o libfoo.so foo.o

// Verify with ldd
ldd libfoo.so

// Compile and link with shared library
gcc -o myprogram main.c -L/path/to/lib -lfoo

// Or with explicit rpath
gcc -o myprogram main.c -L. -lfoo -Wl,-rpath=/home/user/lib

// Check dependencies
ldd myprogram

#include <dlfcn.h>

void *handle = dlopen("./libfoo.so", RTLD_LAZY);
if (!handle) {
 fprintf(stderr, "Error: %s\n", dlerror());
 exit(1);
}

// Clear any existing errors
dlerror();

// Get function pointer
int (*func)(int) = dlsym(handle, "my_function");
char *error = dlerror();
if (error) {
 fprintf(stderr, "Error: %s\n", error);
 dlclose(handle);
 exit(1);
}

// Call the function
int result = func(10);
dlclose(handle);
